/**
 * Postbuild sitemap script
 * 1. Removes sitemap-0.xml (generated by next-sitemap, duplicates dedicated sitemaps)
 * 2. Restores custom sitemap.xml index pointing to all dedicated sitemaps
 * Run after next-sitemap: npm run postbuild
 */

const fs = require('node:fs');
const path = require('node:path');

const PUBLIC_DIR = path.join(process.cwd(), 'public');
const SITE_URL = 'https://www.arteonagency.pl';

function main() {
  // 1. Remove sitemap-0.xml (next-sitemap generates it, but we use dedicated sitemaps)
  const sitemap0 = path.join(PUBLIC_DIR, 'sitemap-0.xml');
  if (fs.existsSync(sitemap0)) {
    fs.unlinkSync(sitemap0);
    console.log('✓ Removed sitemap-0.xml (replaced by dedicated sitemaps)');
  }

  // 2. Find all dedicated sitemap files
  const sitemapFiles = fs.readdirSync(PUBLIC_DIR)
    .filter(f => f.startsWith('sitemap-') && f.endsWith('.xml'))
    .sort();

  // 3. Write sitemap index
  const entries = sitemapFiles
    .map(f => `<sitemap><loc>${SITE_URL}/${f}</loc></sitemap>`)
    .join('\n');

  const sitemapIndex = [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">',
    entries,
    '</sitemapindex>',
  ].join('\n');

  fs.writeFileSync(path.join(PUBLIC_DIR, 'sitemap.xml'), sitemapIndex, 'utf8');
  console.log(`✓ Processed ${sitemapFiles.length} sitemap files for hreflang`);
}

main();
